import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is Ohm's Law?", a: "Ohm's Law states that the current through a conductor is directly proportional to the voltage across it and inversely proportional to its resistance: V = I  x  R, where V is voltage in volts, I is current in amperes, and R is resistance in ohms. It was discovered by German physicist Georg Ohm in 1827." },
  { q: "What is electrical power in a circuit?", a: "Electrical power (P) is the rate at which energy is consumed or transferred, measured in watts (W). P = V  x  I = I-  x  R = V- / R. All three formulas are equivalent - use whichever two values you know. A 60-watt lightbulb on 120V draws 0.5 A. A 100W bulb draws 0.83 A." },
  { q: "What is the difference between AC and DC?", a: "DC (Direct Current) flows in one direction - like batteries and USB power. AC (Alternating Current) periodically reverses direction at a set frequency - like household outlets (60 Hz in the US, 50 Hz in Europe). Ohm's Law applies to DC directly; for AC with reactive components, impedance (Z) replaces resistance." },
  { q: "How do I measure resistance with a multimeter?", a: "Set the multimeter to resistance ( ohm) mode. Disconnect the component from the circuit. Touch the probes to both ends of the component - the display shows resistance. Never measure resistance in a live circuit; always disconnect power first to protect both yourself and the meter." },
  { q: "What is impedance and how does it differ from resistance?", a: "Resistance (R) is opposition to current in DC circuits - it doesn't change with frequency. Impedance (Z) is the total opposition in AC circuits, including resistance plus reactance from inductors and capacitors. Impedance is frequency-dependent. For pure resistors, Z = R. For AC analysis: Z = - + X- where X is reactance." },
  { q: "What are common voltage and current levels in everyday electronics?", a: "Common levels: USB (5V, up to 3A), AA battery (1.5V), car battery (12V), household outlet US (120V, 15A circuit), household outlet EU (230V), industrial (208-480V 3-phase). Safe current thresholds: 1 mA = barely perceptible, 10 mA = painful, 100 mA = potentially fatal. Voltage  x  current = power." },
  { q: "How does resistor color coding work?", a: "Standard resistors use colored bands to indicate resistance. For 4-band resistors: Band 1 (first digit) + Band 2 (second digit) + Band 3 (multiplier) + Band 4 (tolerance). Color values: Black=0, Brown=1, Red=2, Orange=3, Yellow=4, Green=5, Blue=6, Violet=7, Gray=8, White=9. Gold band = - tolerance." },
  { q: "What is Kirchhoff's Law and how does it relate to Ohm's Law?", a: "Kirchhoff's Voltage Law (KVL): the sum of all voltages around any closed loop equals zero. Kirchhoff's Current Law (KCL): the sum of currents entering a node equals the sum leaving it. These laws, combined with Ohm's Law, allow you to solve any DC circuit - they're the mathematical foundation of circuit analysis." },
];

const OHMS_REFERENCE = [
  ["Household outlet (US)", "120V", "15A max", "1,800W max"],
  ["USB-A standard", "5V", "0.5A", "2.5W"],
  ["USB-C PD", "5-20V", "up to 5A", "up to 100W"],
  ["Car battery", "12V", "varies", "varies"],
  ["LED lamp (typical)", "120V", "0.075A (75mA)", "9W"],
  ["Hair dryer", "120V", "12.5A", "1,500W"],
  ["Electric oven", "240V", "25-50A", "6,000-12,000W"],
  ["9V battery", "9V", "small capacity", "~500mA max"],
];

type SolveFor = "voltage" | "current" | "resistance" | "power";

export default function OhmsLawCalculator() {
  const [solveFor, setSolveFor] = useState<SolveFor>("voltage");
  const [voltage, setVoltage] = useState(12);
  const [current, setCurrent] = useState(2);
  const [resistance, setResistance] = useState(6);

  const v = solveFor === "voltage" ? current * resistance : voltage;
  const i = solveFor === "current" ? voltage / resistance : current;
  const r = solveFor === "resistance" ? voltage / current : resistance;
  const p = v * i;

  const result = solveFor === "voltage" ? v : solveFor === "current" ? i : solveFor === "resistance" ? r : p;
  const unit = solveFor === "voltage" ? "V" : solveFor === "current" ? "A" : solveFor === "resistance" ? " ohm" : "W";
  const label = solveFor.charAt(0).toUpperCase() + solveFor.slice(1);

  return (
    <>
      <SEOHead
        title="Free Ohm's Law Calculator Online - Calculate Voltage Current Resistance and Power Instantly | CalcHive"
        description="Free online Ohm's Law calculator. Solve for voltage, current, resistance or power using Ohm's Law V = I x R instantly. 100% free for electronics students and engineers, no signup required."
        canonical="/ohms-law-calculator"
        keywords="free ohms law calculator, ohm's law calculator online free, voltage current resistance calculator free, V=IR calculator free, electronics ohm's law tool free"
        category="Electrical Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-950/50 px-3 py-1 rounded-full mb-4 inline-block">Electronics</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Ohm's Law Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free ohms law calculator to solve for voltage, current, resistance, or power using V = I x R. This ohm's law calculator online free also works as a voltage current resistance calculator free, V=IR calculator free, and electronics ohm's law tool free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex flex-wrap gap-2 mb-6">
          {(["voltage", "current", "resistance", "power"] as SolveFor[]).map(v => (
            <button key={v} onClick={() => setSolveFor(v)} className={`flex-1 min-w-[120px] py-2 rounded-xl text-sm font-semibold border capitalize transition-all ${solveFor === v ? "bg-yellow-500 text-white border-yellow-500" : "bg-card text-muted-foreground border-border hover:border-yellow-400"}`}>Solve for {v}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            {solveFor !== "voltage" && <SliderInput id="voltage" label="Voltage (V)" value={voltage} min={0.001} max={1000} step={0.1} onChange={setVoltage} format={v => `${v.toFixed(1)} V`} testId="input-voltage" />}
            {solveFor !== "current" && solveFor !== "power" && <SliderInput id="current" label="Current (A)" value={current} min={0.001} max={100} step={0.001} onChange={setCurrent} format={v => `${v.toFixed(3)} A`} testId="input-current" />}
            {solveFor !== "resistance" && solveFor !== "power" && <SliderInput id="resistance" label="Resistance ( ohm)" value={resistance} min={0.001} max={10000} step={0.1} onChange={setResistance} format={v => `${v.toFixed(1)}  ohm`} testId="input-resistance" />}
            {solveFor === "power" && <SliderInput id="current2" label="Current (A)" value={current} min={0.001} max={100} step={0.001} onChange={setCurrent} format={v => `${v.toFixed(3)} A`} testId="input-current2" />}
          </div>
          <motion.div key={`${solveFor}-${result}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-yellow-500 to-yellow-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{label}</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-value">{isFinite(result) ? result.toFixed(4) : "-"} {unit}</p>
            </div>
            <div className="grid grid-cols-4 gap-2">
              {[
                { label: "Voltage", value: `${v.toFixed(3)} V` },
                { label: "Current", value: `${i.toFixed(3)} A` },
                { label: "Resistance", value: `${r.toFixed(3)}  ohm` },
                { label: "Power", value: `${p.toFixed(3)} W` },
              ].map(({ label: l, value }) => (
                <div key={l} className={`border rounded-xl p-3 text-center ${label === l ? "bg-yellow-50 dark:bg-yellow-950/30 border-yellow-300" : "bg-accent/60 border-border"}`}>
                  <p className="text-xs text-muted-foreground font-medium mb-1">{l}</p>
                  <p className="text-xs font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Use Ohm's Law to Calculate Voltage Current and Resistance for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Ohm's Law and the power formula give four variables - V, I, R, P - and six equations. Know any two values and you can find the other two. These relationships form the core of all basic DC circuit analysis.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>V = I  x  R     (Voltage = Current  x  Resistance)</p>
            <p>I = V / R     (Current = Voltage  x  Resistance)</p>
            <p>R = V / I     (Resistance = Voltage  x  Current)</p>
            <p>P = V  x  I     (Power = Voltage  x  Current)</p>
            <p>P = I-  x  R   (Power from Current and Resistance)</p>
            <p>P = V- / R   (Power from Voltage and Resistance)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the Formula V = I x R Works in Electronics</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Device/Scenario", "Voltage", "Current", "Power"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {OHMS_REFERENCE.map(([device, vv, ii, pp]) => (
                  <tr key={device} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{device}</td>
                    <td className="py-2.5 px-4 text-yellow-600 dark:text-yellow-400 font-bold">{vv}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{ii}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{pp}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Ohm's Law Tool for Students and Engineers</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Wire Gauge (AWG)", "Max Ampacity", "Resistance per 1000 ft", "Typical Use"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["14 AWG", "15 A", "2.525  ohm", "Standard household circuit"],
                  ["12 AWG", "20 A", "1.588  ohm", "Kitchen, bathroom outlets"],
                  ["10 AWG", "30 A", "0.999  ohm", "Dryers, AC units"],
                  ["8 AWG", "40 A", "0.628  ohm", "Electric ranges"],
                  ["6 AWG", "55 A", "0.395  ohm", "Sub-panels"],
                ].map(([gauge, amp, res, use]) => (
                  <tr key={gauge} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-bold text-yellow-600 dark:text-yellow-400">{gauge}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{amp}</td>
                    <td className="py-2.5 px-4 font-mono text-foreground">{res}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{use}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/ohms-law-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


